// CSD_RATIONALE_BEGIN
// This strategy starts with unconstrained generation to produce initial text,
// then switches to constrained generation when the left delimiter is encountered
// and the prefix is not complete. It continues until the maximum number of steps
// is reached or the prefix becomes complete.
// CSD_RATIONALE_END

var delim := new Delimiter(LeftDelimiter, RightDelimiter);
    var helpers := new CSDHelpers(lm, parser, delim);
    helpers.DelimitersInLMAlways();
    var stepsLeft := maxSteps;
    var generated := [];
    var stepCounter := 0;

    while (stepsLeft > 0)
    {
        invariant lm.ValidTokensIdsLogits()
        invariant 0 <= stepsLeft <= maxSteps
        invariant |generated| + stepsLeft == maxSteps
        invariant helpers.ConstrainedWindowValid(generated)
        decreases stepsLeft

        var next, newSteps: Token;

        // If we're inside the constrained window, use ConstrainedStep
        if (helpers.InsideDelimitedWindow(generated))
        {
            (next, newSteps) := helpers.ConstrainedStep(prompt, generated, stepsLeft);
        }
        else
        {
            // Otherwise, use UnconstrainedStep
            (next, newSteps) := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
        }

        generated := generated + [next];
        stepsLeft := newSteps;

        // Increment step counter
        stepCounter := stepCounter + 1;

        // Exit loop if we've exceeded the maximum number of steps
        if (stepCounter > maxSteps)
        {
            generated := helpers.RollbackToValidPrefix(generated);
            stepsLeft := 0;
        }
    }

    remainingSteps := stepsLeft;

